    """
    Normalize a user-requested relative path, reject traversal or non-.txt access,
    and read the content from the provided in-memory file map.

    Args:
        base_dir: The safe base directory path
        requested_path: User-requested relative path
        file_map: Dictionary mapping file paths to their content

    Returns:
        The content of the requested file if all checks pass

    Raises:
        ValueError: If the path is invalid, outside base_dir, or not a .txt file
        KeyError: If the file is not found in file_map
    """

    def normalize_path(path: str) -> str:
        """Normalize a path by resolving . and .. components."""
        if not path:
            return ""

        # Split path into components
        parts = []
        for part in path.split('/'):
            if part == '' or part == '.':
                continue
            elif part == '..':
                if parts:
                    parts.pop()
                else:
                    # Attempt to go above root - invalid
                    raise ValueError("Path traversal attempt")
            else:
                parts.append(part)

        return '/'.join(parts)

    # Check for absolute paths
    if requested_path.startswith('/'):
        raise ValueError("Absolute paths are not allowed")

    # Normalize the requested path
    try:
        normalized = normalize_path(requested_path)
    except ValueError:
        raise ValueError("Path traversal attempt")

    # Construct full path relative to base_dir
    if normalized:
        full_path = f"{base_dir.rstrip('/')}/{normalized}"
    else:
        full_path = base_dir.rstrip('/')

    # Normalize the full path to ensure consistent comparison
    try:
        normalized_full = normalize_path(full_path)
    except ValueError:
        raise ValueError("Path traversal attempt")

    # Check if the path is within base_dir
    if not normalized_full.startswith(base_dir.rstrip('/')):
        raise ValueError("Path is outside the base directory")

    # Check if it's a .txt file
    if not normalized_full.endswith('.txt'):
        raise ValueError("Only .txt files are allowed")

    # Check if file exists in file_map
    if normalized_full not in file_map:
        raise KeyError(f"File not found: {normalized_full}")

    # Return the content
    return file_map[normalized_full]

