        where_clause = where_clause.strip().upper()

        # Supported operators
        operators = ['=', '!=', '<', '>', '<=', '>=']

        # Find which operator is being used
        op = None
        for operator in operators:
            if operator in where_clause:
                op = operator
                break

        if not op:
            raise ValueError("Invalid WHERE clause: no valid operator found")

        # Split into column and value parts
        parts = where_clause.split(op)
        if len(parts) != 2:
            raise ValueError("Invalid WHERE clause format")

        column = parts[0].strip()
        value_str = parts[1].strip()

